REQUIRED_FIELDS = [
    'contract_number',
    'contract_day',
    'contract_month',
    'contract_year',
    'contract_city',
    'intern_full_name',
    'internship_position',
    'internship_start_date',
    'internship_duration_text',
    'internship_access_resources',
    'internship_duties',
    'intern_passport_number',
    'intern_passport_issued_by',
    'intern_passport_issue_date',
    'intern_passport_division_code',
    'intern_email',
    'intern_phone',
    'intern_sign_name',
]

async def run(args, state):
    updates = args.get('updates')
    if not isinstance(updates, dict):
        raise ValueError('updates должен быть объектом')

    variables = state.get('variables')
    if variables is None:
        variables = {}
        state['variables'] = variables
    if not isinstance(variables, dict):
        raise ValueError('state.variables должен быть объектом')

    draft = variables.get('contract_draft')
    if draft is None:
        draft = {}
        variables['contract_draft'] = draft
    if not isinstance(draft, dict):
        raise ValueError('state.variables.contract_draft должен быть объектом')

    allowed = set(REQUIRED_FIELDS)
    for key, value in updates.items():
        if key not in allowed:
            continue

        if key == 'internship_duties':
            if isinstance(value, list):
                normalized = []
                for item in value:
                    if isinstance(item, str) and item.strip():
                        normalized.append(item.strip())
                if normalized:
                    draft[key] = normalized
            continue

        if isinstance(value, str):
            text = value.strip()
            if text:
                draft[key] = text
            continue

        if value is not None:
            draft[key] = value

    missing = []
    for field in REQUIRED_FIELDS:
        value = draft.get(field)
        if field == 'internship_duties':
            if not (isinstance(value, list) and value):
                missing.append(field)
            continue
        if not (isinstance(value, str) and value.strip()):
            missing.append(field)

    variables['contract_draft'] = draft
    variables['contract_missing_fields'] = missing
    variables['contract_missing_count'] = len(missing)
    variables['contract_ready'] = len(missing) == 0

    return {
        'draft': draft,
        'missing_fields': missing,
        'ready': len(missing) == 0,
    }

